def _with_aliases(prefix: str, palettes: dict[str, list[str]]) -> dict[str, list[str]]:
    registry: dict[str, list[str]] = {}
    for name, colors in palettes.items():
        registry[f"{prefix}_{name}"] = list(colors)
    return registry


